<pre><code data-type="">class Solution {
    private void helper(List&lt;Integer&gt; result, int carry, int digit, int low, int high){
        if(carry &gt; high) {
   return;
  }
  if(carry &gt;= low) {
   result.add(carry);
  }
        if(digit + 1 &lt;= 10){
      helper(result, carry * 10 + digit, digit + 1, low, high);
        }
    }
    public List&lt;Integer&gt; sequentialDigits(int low, int high) {
        List&lt;Integer&gt; result = new ArrayList&lt;&gt;();

  for (int digit = 1; digit &lt;= 9; digit++) {
   helper(result, 0, digit, low, high);
  }

        Collections.sort(result);

  return result;

